'use strict';

const fs = require('fs');
const path = require('path');
const config = require('../config.js');
const { allProducts } = require('../core/products.js');
const { AppError } = require('../lib/errors.js');

const SUPPORTED = ['csv', 'json'];

function exportProducts(args) {
  const idx = args.indexOf('--format');
  const format = idx !== -1 ? args[idx + 1] : 'csv';

  if (!SUPPORTED.includes(format)) {
    throw new AppError(`unsupported format: ${format}`, 2);
  }

  const products = allProducts();
  if (!fs.existsSync(config.outputDir)) {
    fs.mkdirSync(config.outputDir, { recursive: true });
  }

  const outPath = path.join(config.outputDir, `products.${format}`);
  let content;

  if (format === 'csv') {
    const rows = products.map((p) => `${p.id},${p.name},${p.price}`);
    content = ['id,name,price', ...rows].join('\n') + '\n';
  } else {
    content = JSON.stringify(products, null, 2) + '\n';
  }

  fs.writeFileSync(outPath, content);
  return [`exported ${products.length} products to ${outPath}`];
}

module.exports = { exportProducts };

