const config = require('../config.js');
const { allCustomers } = require('../core/customers.js');
const { AppError } = require('../lib/errors.js');

const SUPPORTED = ['csv', 'json'];

function exportCustomers(args) {
  const idx = args.indexOf('--format');
  const format = idx !== -1 ? args[idx + 1] : 'csv';

  if (!SUPPORTED.includes(format)) {
    throw new AppError(`unsupported format: ${format}`, 2);
  }

  const customers = allCustomers();
  if (!fs.existsSync(config.outputDir)) {
    fs.mkdirSync(config.outputDir, { recursive: true });
  }

  const outPath = path.join(config.outputDir, `customers.${format}`);
  let content;

  if (format === 'csv') {
    const rows = customers.map((c) => `${c.id},${c.name},${c.email}`);
    content = ['id,name,email', ...rows].join('\n') + '\n';
  } else {
    content = JSON.stringify(customers, null, 2) + '\n';
  }

  fs.writeFileSync(outPath, content);
  return [`exported ${customers.length} customers to ${outPath}`];
}

module.exports = { exportCustomers };

